import{c as a,Q as t,j as s,m as i}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Hermes Agent工作流：用顶级AI Newsletter构建第二大脑 — @lxfater","description":"","frontmatter":{"title":"Hermes Agent工作流：用顶级AI Newsletter构建第二大脑 — @lxfater","author":"lxfater（@lxfater）","date":"2026-04-23T00:00:00.000Z","source":"https://x.com/lxfater/status/2047150392274993624","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-23-@lxfater-993624.md","filePath":"research/tweets/2026-04-23-@lxfater-993624.md","lastUpdated":1779898012000}'),l={name:"research/tweets/2026-04-23-@lxfater-993624.md"};function n(r,e,h,o,p,d){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="hermes-agent工作流-用顶级ai-newsletter构建第二大脑-—-lxfater" tabindex="-1">Hermes Agent工作流：用顶级AI Newsletter构建第二大脑 — @lxfater <a class="header-anchor" href="#hermes-agent工作流-用顶级ai-newsletter构建第二大脑-—-lxfater" aria-label="Permalink to &quot;Hermes Agent工作流：用顶级AI Newsletter构建第二大脑 — @lxfater&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/lxfater/status/2047150392274993624" target="_blank" rel="noreferrer">https://x.com/lxfater/status/2047150392274993624</a><strong>作者</strong>：lxfater（@lxfater） <strong>發布日期</strong>：2026-04-23 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：Twitter Article <strong>統計</strong>：395 likes · 96 retweets · 916 bookmarks · 157,726 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>每天出新东西，你也每天在刷 但关上手机那一刻：什么都没进脑子 刷了那么多，说不出自己学到了啥 AI越来越聪明，你越来越像个局外人 这不是你不够努力，是大多数人学AI，从一开始就把劲儿使错了地方 我有段时间也是这样，直到我把学习方式彻底反过来 把这套方法跑在 Hermes Agent 上之后 学AI这件事，变了，甚至我的文章输出变好了，连续出了18w，17w，86w的文章： [圖 1] [圖 2] [圖 3] 今天，这篇把完整工作流拆给你： 第一步：换掉信息源（顶级AI Newsletter清单，从50+里筛出来的） 第二步：让 Hermes Agent 每天替你筛选消化，构建第二大脑 第三步：倒逼出能打的输出 再也不怕学不动AI！！ 下面，我们先说如何让Agent阅读到高质量AI信息源！！</p><h1 id="换信息源-用hermes构建获取管道" tabindex="-1">换信息源，用Hermes构建获取管道 <a class="header-anchor" href="#换信息源-用hermes构建获取管道" aria-label="Permalink to &quot;换信息源，用Hermes构建获取管道&quot;">​</a></h1><p>让Agent能通过newsletter的方式获取到高质量信息，我们就必须安装下图一步一步进行配置。 当然配置完毕后，你对邮件信息的处理能力将从原始时代提升到火器时代。 下面整个工作流的示意图： [圖 4] 配置之前，我们需要聊一个很重要的事情。</p><h2 id="高质量ai-newsletter清单" tabindex="-1">高质量AI newsletter清单 <a class="header-anchor" href="#高质量ai-newsletter清单" aria-label="Permalink to &quot;高质量AI newsletter清单&quot;">​</a></h2><p>没有好的信息源，我们学到的只是噪音。下面这些 newsletter 是我半年里从 50+ 源里筛下来的高质量信息源，希望对你有帮助。</p><ul><li>The Rundown AI（therundown.ai）：每日 AI 产业动态，通俗易懂、密度高</li><li>TLDR AI（tldr.tech）：5 分钟科技简报，AI 加编程加产品精华浓缩</li><li>The Neuron（theneurondaily.com）：面向非技术读者的 AI 日报，3 分钟读完</li><li>Ben&#39;s Bites（bensbites.com）：Ben Tossell 的 AI 日报，工具圈消息源</li><li>Latent Space（latent.space）：swyx 开发者简报，未公开项目加工程视角</li><li>Smol AI News（smol.ai/news）：Discord、Reddit 等 AI 社区圈内直击</li><li>Interconnects（interconnects.ai）：Nathan Lambert 的 RLHF、模型训练深度专栏</li><li>One Useful Thing（oneusefulthing.org）：Ethan Mollick 的 AI 实用洞察（学术加工作场景）</li><li>AI Breakfast（aibreakfast.beehiiv.com）：每周一份 AI 新闻早餐，系统回顾加深度讨论</li><li>Every（every.to）：科技与商业的下一步，资深专家战略分析 你可能会问：为什么不看国内公众号信息？ AI 这种变化快的赛道，真正有信号的源头全在海外 newsletter。公众号被洗稿一层一层过滤，你看到的时候已经是二手信息。 学东西，垃圾进垃圾出，源头得把控好！！ 接下来，我们构建newslatter信息到Agent的管道，让最高质量的人类信息和我们的Agent接触！！</li></ul><h2 id="第一步-给hermes配置邮箱" tabindex="-1">第一步：给Hermes配置邮箱 <a class="header-anchor" href="#第一步-给hermes配置邮箱" aria-label="Permalink to &quot;第一步：给Hermes配置邮箱&quot;">​</a></h2><p>为了构建这套系统，我们首先得给Hermes配置一个邮箱，这样才能收到前面的AI高质量信息源的邮件。 那具体如何给agent申请邮箱呢？ 打开 <a href="https://claw.163.com/?channel=lxfater%EF%BC%88%E7%BD%91%E6%98%93%E9%82%AE%E7%AE%B1%E6%96%B0%E5%87%BA%E7%9A%84" target="_blank" rel="noreferrer">https://claw.163.com/?channel=lxfater（网易邮箱新出的</a> Agent 专属邮箱产品），报名内测（填平常你的邮箱），等邀请码邮件。 因为在内测阶段，需要输入可以用我的专属激活码：CLAW3C02D3891B6C( 邀请码使用上限200次,先到先得)，然建主邮箱，比如 <a href="mailto:XXXX@claw.163.com" target="_blank" rel="noreferrer">XXXX@claw.163.com</a>， [圖 5] 但这还没完，为了让Agent能使用它的邮箱，你必须安装一个工具！！</p><h2 id="第二步-装-mail-cli-让hermes有眼睛" tabindex="-1">第二步：装 mail-cli，让Hermes有眼睛 <a class="header-anchor" href="#第二步-装-mail-cli-让hermes有眼睛" aria-label="Permalink to &quot;第二步：装 mail-cli，让Hermes有眼睛&quot;">​</a></h2><p>一旦你安装完mail-cli后，Agent 能读邮件、能搜关键词、能拉正文，邮箱正式变成 Agent 的输入管道 如何做呢？ 终端按顺序敲这 4 条：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. 全局安装 mail-cli</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @clawemail/mail-cli</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. 把 API Key 写进系统钥匙串（上一步在 Dashboard 拿的那个）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mail-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apikey</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ck_live_xxxxxxxxxxxxxxxx</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. 登录主邮箱</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mail-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lxfater@claw.163.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. 测试连接通了没</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mail-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre></div><p>上面缺失ApiKey，可以按下面获取方式获取： [圖 6] 同时为了让Hermes学会使用clawmail，我们在Hermes简单输入下面提示词：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://claw.163.com/projects/doc/ 阅读这个CLI文档，然后制作一个Skill来专门来操纵这CLI。</span></span></code></pre></div><p>利用Hermes自学习能力，很快就学会使用这个CLI了，具体如下图 [圖 7] 做到这里，你可能会说，要是我还想用邮箱干客服工作呢，那不就搞混了？ 我的解决方法就是专门建一个子邮箱，专门来接收newsletter。</p><h2 id="第三步-构建-newsletter-专属子邮箱" tabindex="-1">第三步：构建 newsletter 专属子邮箱 <a class="header-anchor" href="#第三步-构建-newsletter-专属子邮箱" aria-label="Permalink to &quot;第三步：构建 newsletter 专属子邮箱&quot;">​</a></h2><p>安装一个专属的newsletter的子邮箱，能隔离不同的信息，提升Agent处理信息的效率。 终端里敲：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mail-cli clawemail create \\</span></span>
<span class="line"><span>  --prefix newsletter \\</span></span>
<span class="line"><span>  --type sub \\</span></span>
<span class="line"><span>  --display-name &quot;Newsletter Bot&quot;</span></span></code></pre></div><p>然后去 Dashboard 把这个子邮箱的通讯规则打开：</p><ol><li>Dashboard → Agent 邮箱管理 → 选中这个子邮箱 → 通讯规则</li><li>选 开放外部通信</li><li>收信范围选 所有人（newsletter 发件域太杂，白名单维护不过来） 具体如下图： [圖 8] 看到这里，你可能很累，但胜利就在眼前，哈哈哈。 接下来，马上教你如何用Agent订阅newsletters。</li></ol><h2 id="第四步-子邮箱订阅newsletter" tabindex="-1">第四步： 子邮箱订阅newsletter <a class="header-anchor" href="#第四步-子邮箱订阅newsletter" aria-label="Permalink to &quot;第四步： 子邮箱订阅newsletter&quot;">​</a></h2><p>做完这步你所有的 newsletter 订阅就在一个专属的子邮箱里面，这样以后你还想做其他邮件自动化时候，比如专门用agent做企业客服，邮件就不会搞混了。 Agent订阅newsletter很简单： 以后看到新 newsletter，订阅框直接填 <a href="mailto:XXX.newsletter@claw.163.com" target="_blank" rel="noreferrer">XXX.newsletter@claw.163.com</a> 确认邮件到后，让 Hermes 直接提取出确认地址，地址输入浏览器就能确认成功，需要回复邮件进行人机检查的，让它帮忙回复。 [圖 9] 到这里你已经比 80% 的人领先一档，他们还在 Gmail 里用人肉读 newsletter。而你的 newsletter 已经进了 Agent 专属邮箱，Agent 随时能读 但这篇教程真正的重点是让Agent每天替你筛选、消化、这些高质量新资源，并产出一份你真能用的日报，并且进行真正的主题研究。 所以请往下👇看</p><h1 id="二、筛选消化信息-hermes构建第二大脑" tabindex="-1">二、筛选消化信息，Hermes构建第二大脑 <a class="header-anchor" href="#二、筛选消化信息-hermes构建第二大脑" aria-label="Permalink to &quot;二、筛选消化信息，Hermes构建第二大脑&quot;">​</a></h1><p>下面我将介绍让我最近文章输出能力大涨的Hermes-Agent学习流程： [圖 10]</p><h2 id="第一步-扫-digest" tabindex="-1">第一步：扫 Digest <a class="header-anchor" href="#第一步-扫-digest" aria-label="Permalink to &quot;第一步：扫 Digest&quot;">​</a></h2><p>我们可以利用Agent来初筛一遍newsletter，这样既节约时间，也不会漏掉热点。 ClawEmail 官方自带一个能力，开启之后每天早上一封日报邮件到你 Gmail里面是今天所有 newsletter 的摘要加推荐。 输入下面命令安装：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx skills add https://claw.163.com/gitea-web/s/daily-report.git</span></span></code></pre></div><p>这里有个有趣的点，大多数人订 Digest 是为了让 AI 帮他读完省时间，大概知道一些AI新闻，但我还有它干一件事：挑出今天最值得深读的那一篇文章。 下面是本文的核心</p><h2 id="第二步-让-llm-wiki-将newsletter拆进知识库" tabindex="-1">第二步：让 LLM Wiki 将newsletter拆进知识库 <a class="header-anchor" href="#第二步-让-llm-wiki-将newsletter拆进知识库" aria-label="Permalink to &quot;第二步：让 LLM Wiki 将newsletter拆进知识库&quot;">​</a></h2><p>终于到了最核心的部分，利用 LLM Wiki 技术去消化知识。 你可能会一脸懵，LLM Wiki 是啥？ 我打个比方： 它像个实习生，每天你扔一篇文章给它，它把里面的概念、实体、主张、开放问题一个个拆出来，每个做一张索引卡片贴在墙上，再用线把这张新卡片和墙上已有的相关卡片连起来，久了这堵墙就是一张活的知识图。 这是 Karpathy 2026 年提出的：他说 RAG 检索太窄，LLM 真正该干的是知识编译器。一经提出，火爆全球。 具体怎么操作？ 让Hermes给出邮箱里面你感兴趣的文章，告诉它：这篇编译到我的 Wiki 跑完之后，你会获得一个互相链接的Markdown文件，构成一个知识网络，彼此用链接连起来。 打开Obsidian知识图图谱功能： [圖 11] 在这个图里面找到你不懂的概念，不断问Hermes拆解概念，你的知识图上现在有一堆互相勾连的概念。 [圖 12] 旧概念因为今天这篇又加了一条新论据，同时新旧概念第一次被连到一起 这个模式符合认知科学，因而会带来个神奇的效果：就是你读 1 篇等于刷新了 10 篇！ [圖 13] 别人每天刷 100条 推文，一天就忘。你一天一篇，自动将新知识和老知识关联，知识图一天厚一点，学进去就不易遗忘。 题外话：假如你还对LLM Wiki感兴趣，可以看下面这篇文章： 做完这一切后，有一个更意义的问题：这些东西怎么变成一篇 X 文章，如何获得产出呢？</p><h1 id="三、用hermes-llm-wiki倒逼产出" tabindex="-1">三、用Hermes LLM Wiki倒逼产出 <a class="header-anchor" href="#三、用hermes-llm-wiki倒逼产出" aria-label="Permalink to &quot;三、用Hermes LLM Wiki倒逼产出&quot;">​</a></h1><p>学习就是为了输出，光学不练，就相当于没学，所以下面是输出实操： 很简单！！把 Wiki 里的 index文件给 AI ，它就会去读你的wiki了 下面列举两种常见输出方式：</p><h2 id="做信息图" tabindex="-1">做信息图 <a class="header-anchor" href="#做信息图" aria-label="Permalink to &quot;做信息图&quot;">​</a></h2><p>Hermes Agent 内置一个信息图命令行，底层跑的是宝玉的信息图 prompt，Hermes 官方把它收进了内置命令了。 把 Wiki index 地址给AI，问一个概念：Verification Loop是什么？它扫一里面相关主题的知识，直接吐出一张下面的信息图。 [圖 14] 这还不是最有价值的，我们还可以用这个来串联知识，进而提高文章质量。</p><h2 id="自己写文章-ai-做脑爆" tabindex="-1">自己写文章，AI 做脑爆 <a class="header-anchor" href="#自己写文章-ai-做脑爆" aria-label="Permalink to &quot;自己写文章，AI 做脑爆&quot;">​</a></h2><p>大多数人以为 AI 写文章就是 AI 帮你写，但真正让你写出好文章还是你自己把事情想明白,AI 只做脑爆，提高多做可能性。 写的时候碰到想不清楚的地方，对着Hermes 问：</p><ol><li>这个概念我上周读过哪几篇支持？</li><li>那个观点我怎么反驳？</li><li>还有哪些角度我没考虑到？ 让Hermes 利用llmwiki功能给你灵感和解决你的盲点 写好文章后，如果你不想排版，可以参考我这篇文章，自动AI排版和发布。</li></ol><h1 id="最后一件事" tabindex="-1">最后一件事 <a class="header-anchor" href="#最后一件事" aria-label="Permalink to &quot;最后一件事&quot;">​</a></h1><p>这整套流程用的是网易邮箱新出的 ClawEmail：这是一种新邮箱，是给Agent 用的。 这也是电子邮件的未来！！ 如果你对给Agent接入邮箱感兴趣，想自己搞一个，可以到官网 <a href="https://claw.163.com/?channel=lxfater%E6%8A%A5%E5%90%8D%E5%86%85%E6%B5%8B" target="_blank" rel="noreferrer">https://claw.163.com/?channel=lxfater报名内测</a> 内测名额有限，我这有个邀请码可以直接通过：CLAW3C02D3891B6C，邀请码使用上限200次 本次文章就这样，假如你觉得有用，欢迎点赞转发。 #网易邮箱 #网易邮箱ClawEmail #ClawEmail #AI工具 #跨平台沟通 #Agent跨平台互通 #多Agent协同 #养龙虾 #网易龙虾邮箱</p><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：用 Hermes Agent + Agent 專屬邮箱（ClawEmail）自動化 AI Newsletter 訂閱-消化-輸出工作流，核心是 LLM Wiki 技術將文章轉化為可查詢知識庫。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>信息攝入問題的根源：學 AI 但知識沒有進入長期記憶，需要主動的消化和輸出環節</li><li>LLM Wiki 概念：文章 → 知識點化 → 可查詢個人 wiki，形成真正的第二大腦</li><li>Agent 專屬邮箱（ClawEmail）是構建信息管道的基礎設施</li><li>輸出倒逼輸入：以「寫出能打的文章」為目標驅動信息攝取</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>信息源：從 50+ 篩選出 10 個頂級 newsletter（含 Latent Space、Interconnects 等工程向）</li><li>ClawEmail：網易邮箱的 Agent 專屬邮箱（內測，邀請碼 CLAW3C02D3891B6C，限 200 次）</li><li>mail-cli：讓 Agent 可讀邮件的 CLI 工具</li><li>作者成果：連續產出 18 萬、17 萬、86 萬閱讀的文章</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>文章含明顯推廣成分（ClawEmail 邀請碼、網易邮箱 hashtag），中立性存疑</li><li>LLM Wiki 技術描述模糊，未說明具體實現方式（是 RAG？是 structured memory？）</li><li>Newsletter 清單本身有高價值（Latent Space、Interconnects 是工程師 community 的重要信號源）</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>5/10</td><td>Newsletter 清單可直接用；LLM Wiki 概念對 cc-workspace 的 research 工作流有啟發</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>LLM Wiki 知識點化概念有洞見，但 ClawEmail 推廣降低信任度</td></tr><tr><td>C. 證據品質 (20%)</td><td>4/10</td><td>個人使用結果（18w 文章），含商業推廣，可信度打折</td></tr><tr><td>D. 技術深度 (15%)</td><td>4/10</td><td>操作步驟完整，但 LLM Wiki 核心技術說明不充分</td></tr><tr><td>E. 泛化性 (15%)</td><td>5/10</td><td>Newsletter 訂閱自動化跨工具通用，但 Hermes + ClawEmail 特化程度高</td></tr><tr><td><strong>加權總分</strong></td><td><strong>4.7/10</strong></td><td>5×0.3 + 5×0.2 + 4×0.2 + 4×0.15 + 5×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：總分 4.7 低於門檻，含推廣偏差；Newsletter 清單（Latent Space、Interconnects 等）可作為獨立參考，但不需要整合為 SKILL/Rule</p>`,54)])])}const k=a(l,[["render",n]]);export{m as __pageData,k as default};
